Infer({method:'MCMC', burn:10000, samples: 50000, onlyMAP:false}, function() {
  let vocab = ['dogs', 'cats', 'chase', 'sleep', 'stop'];

  var wordToDistribution = mem(function(word) {
    return dirichletDrift({alpha: ones([vocab.length, 1]), concentration: 10});
  });

  var transition = function(word) {
    return categorical({ps: wordToDistribution(word), vs: vocab});
  };

  // Recursively generates words starting from `word`, stopping when 'stop' is emitted.
  // Returns the list of non-stop words produced.
  var generateSentence = function(word) {
    if (word === 'stop') return [];
    var next = transition(word);
    return [word].concat(generateSentence(next));
  };

  // Condition on having observed the sentence "dogs chase cats".
  // Under the bigram model this means:
  //   transition('dogs')  -> 'chase'
  //   transition('chase') -> 'cats'
  //   transition('cats')  -> 'stop'
  var observed = ['dogs', 'chase', 'cats'];
  condition(_.isEqual(generateSentence('dogs'), observed));

  // Return a posterior-predictive sample from the learned distribution
  // over words that follow 'chase'.  Because wordToDistribution is memoized,
  // this draws from the same (now posterior-updated) parameters that were
  // used during conditioning.
  return transition('chase');
})

