var nouns = ['dogs', 'cats'];
var verbs = ['chase', 'sleep'];

// Sample per-POS transition distributions via Dirichlet priors (Dirichlet-drift)
// From 'start': can go to N or V
var startTransPs = dirichlet(Vector([2, 2]));
// From 'N': can go to V or stop
var nTransPs     = dirichlet(Vector([2, 2]));
// From 'V': can go to N or stop
var vTransPs     = dirichlet(Vector([2, 2]));

// Transition: given current POS, sample next POS
var transition = function(pos) {
  if (pos === 'start') {
    return categorical({ ps: startTransPs, vs: ['N', 'V'] });
  } else if (pos === 'N') {
    return categorical({ ps: nTransPs, vs: ['V', 'stop'] });
  } else if (pos === 'V') {
    return categorical({ ps: vTransPs, vs: ['N', 'stop'] });
  } else {
    return 'stop';
  }
};

// Emission: given POS, sample a word
var emit = function(pos) {
  if (pos === 'N') {
    return uniformDraw(nouns);
  } else if (pos === 'V') {
    return uniformDraw(verbs);
  } else {
    return 'stop';
  }
};

// Recursively generate a sentence as an array of words
var generateSentence = function(pos) {
  var nextPos = transition(pos);
  if (nextPos === 'stop') {
    return [];
  } else {
    var word = emit(nextPos);
    return [word].concat(generateSentence(nextPos));
  }
};

